javascript: 
const startButton = document.getElementById('start-button');
const stopButton = document.getElementById('stop-button');
const resetButton = document.getElementById('reset-button');
const elapsedTimeDisplay = document.querySelector('#elapsed-time-display');
let elapsedTime = 0;
let intervalId;

// Add event listeners to buttons
startButton.addEventListener('click', startTimer);
stopButton.addEventListener('click', stopTimer);
resetButton.addEventListener('click', resetTimer);

function startTimer() {
    intervalId = setInterval(() => {
        elapsedTime++;
        const hours = Math.floor(elapsedTime / 3600);
        const minutes = Math.floor((elapsedTime % 3600) / 60);
        const seconds = elapsedTime % 60;
        elapsedTimeDisplay.textContent = `${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
    }, 1000);
    stopButton.disabled = false;
}

function stopTimer() {
    clearInterval(intervalId);
    stopButton.disabled = true;
}

function resetTimer() {
    elapsedTime = 0;
    clearInterval(intervalId);
    elapsedTimeDisplay.textContent = '00:00:00';
    stopButton.disabled = true;
}
